from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent complex sentence.
    """
    if not triples:
        return ""

    # Get the main subject (building name)
    main_subject = triples[0].subject

    # Collect information about the main building
    building_details = {}
    location_chain = []
    temporal_info = {}
    related_entities = {}  # Store info about related entities (architects, etc.)

    for t in triples:
        pred = t.predicate
        obj = t.object

        if t.subject == main_subject:
            building_details[pred] = obj
            if pred in ['buildingStartDate', 'completionDate', 'inaugurationDate',
                       'yearOfConstruction', 'addedToTheNationalRegisterOfHistoricPlaces']:
                temporal_info[pred] = obj
            elif pred in ['isPartOf', 'country', 'state', 'region', 'location']:
                location_chain.append(obj)
        elif pred in ['isPartOf', 'country', 'state', 'region']:
            # Track location hierarchy for chained relationships
            location_chain.append(obj)
        else:
            # Store related entity info (like architect's birthPlace)
            related_entities[t.subject] = {pred: obj}

    # Build the sentence progressively
    parts = []

    # Start with subject and building type
    if 'buildingType' in building_details:
        parts.append(f"{main_subject} is a {building_details['buildingType']}")
    else:
        parts.append(main_subject)

    # Add architect information
    if 'architect' in building_details:
        architect = building_details['architect']
        architect_info = related_entities.get(architect, {})
        if 'birthPlace' in architect_info:
            parts.append(f"designed by {architect}, who was born in {architect_info['birthPlace']}")
        else:
            parts.append(f"designed by {architect}")

    # Add architectural style
    if 'architecturalStyle' in building_details:
        parts.append(f"featuring {building_details['architecturalStyle']} architecture")

    # Add physical characteristics
    if 'floorCount' in building_details:
        parts.append(f"with {building_details['floorCount']} floors")
    if 'height' in building_details:
        parts.append(f"standing {building_details['height']} in height")
    if 'numberOfRooms' in building_details:
        parts.append(f"containing {building_details['numberOfRooms']} rooms")
    if 'bedCount' in building_details:
        parts.append(f"with {building_details['bedCount']} beds")
    if 'floorArea' in building_details:
        parts.append(f"covering {building_details['floorArea']} in floor area")

    # Add financial/ownership info
    if 'cost' in building_details:
        parts.append(f"at a cost of {building_details['cost']}")
    if 'owner' in building_details:
        parts.append(f"owned by {building_details['owner']}")
    if 'developer' in building_details:
        parts.append(f"developed by {building_details['developer']}")
    if 'tenant' in building_details:
        parts.append(f"tenanted by {building_details['tenant']}")
    if 'currentTenants' in building_details:
        parts.append(f"currently housing {building_details['currentTenants']}")

    # Add location information
    if location_chain:
        location_parts = []
        for i, loc in enumerate(location_chain):
            if i == 0:
                location_parts.append(f"located in {loc}")
            else:
                location_parts.append(f"which is in {loc}")
        parts.extend(location_parts)

    # Add temporal information
    if 'completionDate' in temporal_info:
        parts.append(f"completed in {temporal_info['completionDate']}")
    if 'inaugurationDate' in temporal_info:
        parts.append(f"inaugurated on {temporal_info['inaugurationDate']}")
    if 'yearOfConstruction' in temporal_info:
        parts.append(f"built in {temporal_info['yearOfConstruction']}")

    # Add address if available
    if 'address' in building_details:
        parts.append(f"at {building_details['address']}")

    # Add former name if available
    if 'formerName' in building_details:
        parts.append(f"formerly known as {building_details['formerName']}")

    # Add other predicates
    if 'buildingStartDate' in temporal_info:
        parts.append(f"construction began in {temporal_info['buildingStartDate']}")

    # Join all parts into a single fluent sentence
    if len(parts) == 1:
        sentence = parts[0]
    else:
        sentence = parts[0]
        for part in parts[1:]:
            sentence += ", " + part

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

